+        _ = try self.kitty.displayRawRGBA(writer, forward_rgba, BUTTON_SIZE, BUTTON_SIZE, .{
+            .placement_id = Placement.FWD_BTN,
+            .z = 51,
+            .x_offset = x_offset,
+            .y_offset = y_offset,
+        });
+        x_offset += BUTTON_SIZE + BUTTON_PADDING;
